   836→    /// Space / PageDown：視覺向下捲動一頁，到底部則翻到下一張
   837→    /// macOS unflipped: visual bottom = minY ≈ 0, scroll down = decrease Y
   838→    private func scrollPageDownOrNext() {
   839→        let clipView = scrollView.contentView
   840→        let visibleHeight = clipView.bounds.height
   841→        let currentMinY = clipView.bounds.minY
   842→
   843→        // Visual bottom in unflipped coords = minY near 0
   844→        if currentMinY <= Constants.scrollEdgeThreshold {
   845→            goToNextImage()
   846→        } else {
   847→            let newY = max(currentMinY - visibleHeight, 0)
   848→            clipView.scroll(to: NSPoint(x: clipView.bounds.minX, y: newY))
   849→            scrollView.reflectScrolledClipView(clipView)
   850→        }
   851→    }
   852→
   853→    /// PageUp：視覺向上捲動一頁，到頂部則翻到上一張
   854→    /// macOS unflipped: visual top = maxY ≈ docHeight, scroll up = increase Y
   855→    private func scrollPageUpOrPrev() {
   856→        let clipView = scrollView.contentView
   857→        let visibleHeight = clipView.bounds.height
   858→        let currentMinY = clipView.bounds.minY
   859→        let docHeight = scrollView.documentView?.frame.height ?? 0
   860→
   861→        // Visual top in unflipped coords = maxY near docHeight
   862→        let clipMaxY = currentMinY + visibleHeight
   863→        if clipMaxY >= docHeight - Constants.scrollEdgeThreshold {
   864→            goToPreviousImage()
   865→        } else {
   866→            let newY = min(currentMinY + visibleHeight, docHeight - visibleHeight)
   867→            clipView.scroll(to: NSPoint(x: clipView.bounds.minX, y: newY))
   868→            scrollView.reflectScrolledClipView(clipView)
   869→        }
   870→    }
