    /// Menu action entry point — `sender` is the NSMenuItem; ignore it.
    @objc func goToNextImage(_ sender: Any? = nil) {
        navigateNext(amount: 1)
    }

    /// Menu action entry point — `sender` is the NSMenuItem; ignore it.
    @objc func goToPreviousImage(_ sender: Any? = nil) {
