    @objc func togglePageOffset(_ sender: Any? = nil) {
        settings.firstPageIsCover.toggle()
        settings.save()
        saveFolderDualPageSettings()
        if settings.dualPageEnabled {
            rebuildSpreadsAndReload()
        }
